def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_priority = 0
        if ratio > 1:
            base_priority = ratio ** 4 + np.sqrt(ratio)
        elif ratio == 1:
            base_priority = 0
        else:
            log_ratio = np.log(ratio)
            if log_ratio < -2:
                base_priority = -7 * log_ratio + ratio ** 2
            elif log_ratio < -0.5:
                base_priority = -3 * log_ratio + 0.3 * ratio
            else:
                base_priority = -log_ratio + 0.7 * ratio
        penalty = 0
        if capacity < item * 0.3:
            penalty += 3
        elif capacity < item * 0.7:
            penalty += 1.5
        elif capacity > item * 3:
            penalty -= 2
        elif capacity > item * 1.5:
            penalty -= 0.5
        fluctuation = 0
        for j in range(len(bins)):
            if j != i:
                diff = abs(capacity - bins[j])
                if diff < item * 0.1:
                    fluctuation += 0.1
                elif diff > item * 2:
                    fluctuation -= 0.2
        priorities[i] = base_priority + penalty + fluctuation
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        min_priority = 0
    else:
        min_priority = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority + 15
    return priorities
